const d = $input.first().json;

const num = (v, def=0) => (v !== null && v !== undefined && !isNaN(Number(v))) ? Number(v) : def;
const str = (v, def='N/A') => (v && String(v).trim()) ? String(v).trim() : def;

const a1 = d.a1_data || {};
const a2 = d.a2_data || {};
const a3 = d.a3_data || {};
const a4 = d.a4_data || {};
const a5 = d.a5_data || {};
const a6 = d.a6_data || {};
const a7 = d.a7_data || {};
const a8 = d.a8_data || {};

const scoreCompetition = num(a1.outputs?.competitor_density_score ?? a1.competitor_density_score, 50);
const scoreRent = (() => {
  const budget = num(d.monthly_rent);
  const median = num(a2.median_rent?.monthly ?? a2.outputs?.median_rent, budget);
  if (!median || !budget) return 50;
  const ratio = budget / median;
  if (ratio >= 1.2) return 90;
  if (ratio >= 1.0) return 75;
  if (ratio >= 0.8) return 55;
  return 30;
})();
const scoreDemand = num(a3.outputs?.market_demand_score ?? a3.market_demand_score, 50);
const scoreCost   = num(a4.outputs?.cost_score ?? a4.cost_viability_score, 50);
const scoreProfit = num(a5.outputs?.profitability_score ?? a5.profitability_score, 50);

const overallScore = Math.round((scoreCompetition + scoreRent + scoreDemand + scoreCost + scoreProfit) / 5);
const verdict = overallScore >= 75 ? 'Strong Go' :
                overallScore >= 60 ? 'Conditional Go' :
                overallScore >= 45 ? 'Caution' : 'No Go';

const a4Out = a4.outputs || a4;
const a5Out = a5.outputs || a5;

const monthlyRevenue    = num(d.monthly_revenue || a5Out.projected_monthly_revenue || a5Out.monthly_revenue);
const setupCost         = num(d.setup_cost || a4Out.total_setup_cost || a4Out.setup_cost);
const monthlyRent       = num(d.monthly_rent);
const monthlyLabour     = num(a4Out.monthly_labour || a4Out.monthly_staff_cost);
const monthlyOther      = num(a4Out.monthly_other_costs || a4Out.monthly_expenses);
const totalMonthlyCosts = monthlyRent + monthlyLabour + monthlyOther;
const monthlyProfit     = monthlyRevenue - totalMonthlyCosts;
const breakevenMonthly  = Math.round(totalMonthlyCosts);
const breakevenDaily    = Math.round(breakevenMonthly / 30);
const breakevenMonths   = (monthlyProfit > 0 && setupCost > 0) ? Math.ceil(setupCost / monthlyProfit) : 0;

const competitorSummary = a1.outputs?.executive_summary || a1.executive_summary ||
  `Found ${num(a1.outputs?.total_competitors_found ?? a1.total_competitors_found)} competitors nearby. Score: ${scoreCompetition}/100.`;
const rentSummary = a2.summary || a2.outputs?.summary ||
  `Median monthly rent: ${d.currency || 'AUD'} ${num(a2.median_rent?.monthly ?? a2.outputs?.median_rent ?? d.monthly_rent, d.monthly_rent).toLocaleString()}.`;
const demandSummary = a3.outputs?.summary || a3.summary || a3.market_summary ||
  `Market demand score: ${scoreDemand}/100.`;
const costSummary = a4Out.summary || a4Out.cost_summary ||
  `Monthly operating costs: ${d.currency || 'AUD'} ${totalMonthlyCosts.toLocaleString()}.`;
const profitSummary = a5Out.summary || a5Out.profitability_summary ||
  `Projected monthly profit: ${d.currency || 'AUD'} ${monthlyProfit.toLocaleString()}.`;

const swotStr = JSON.stringify({
  strengths:     a1.outputs?.opportunity_gaps?.slice(0,2) || ['Market opportunity identified'],
  weaknesses:    a1.outputs?.key_risks || ['Competition present in area'],
  opportunities: a3.outputs?.growth_opportunities || a8.outputs?.opportunities || ['Growing market'],
  threats:       a3.outputs?.market_threats || a8.outputs?.risks || ['Economic uncertainty']
});
const swot = JSON.parse(swotStr);
const swotMarkdown = `**Strengths:** ${Array.isArray(swot.strengths)?swot.strengths.join(', '):swot.strengths}\n**Weaknesses:** ${Array.isArray(swot.weaknesses)?swot.weaknesses.join(', '):swot.weaknesses}\n**Opportunities:** ${Array.isArray(swot.opportunities)?swot.opportunities.join(', '):swot.opportunities}\n**Threats:** ${Array.isArray(swot.threats)?swot.threats.join(', '):swot.threats}`;

const yr1 = monthlyRevenue * 12;
const growthRate = num(a3.outputs?.projected_growth_rate ?? a3.projected_growth_rate, 0.05);
const yr2 = Math.round(yr1 * (1 + growthRate));
const yr3 = Math.round(yr2 * (1 + growthRate));
const projection = `Year 1: ${d.currency||'AUD'} ${yr1.toLocaleString()} | Year 2: ${d.currency||'AUD'} ${yr2.toLocaleString()} (${Math.round(growthRate*100)}% growth) | Year 3: ${d.currency||'AUD'} ${yr3.toLocaleString()}`;
const plSummary = `Revenue: ${d.currency||'AUD'} ${monthlyRevenue.toLocaleString()}/mo | Rent: ${d.currency||'AUD'} ${monthlyRent.toLocaleString()}/mo | Labour: ${d.currency||'AUD'} ${monthlyLabour.toLocaleString()}/mo | Net: ${d.currency||'AUD'} ${monthlyProfit.toLocaleString()}/mo`;
const sensitivity = `Best case: ${d.currency||'AUD'} ${Math.round(monthlyProfit*1.2).toLocaleString()}/mo | Base: ${d.currency||'AUD'} ${monthlyProfit.toLocaleString()}/mo | Worst: ${d.currency||'AUD'} ${Math.round(monthlyProfit*0.8).toLocaleString()}/mo`;

const fullReport = `# Locatalyze Report: ${d.business_type} @ ${d.address || d.area + ', ' + d.city}\n\n**Overall Score: ${overallScore}/100 — ${verdict}**\n\n## Scores\n| Category | Score |\n|---|---|\n| Competition | ${scoreCompetition}/100 |\n| Rent | ${scoreRent}/100 |\n| Market Demand | ${scoreDemand}/100 |\n| Cost Viability | ${scoreCost}/100 |\n| Profitability | ${scoreProfit}/100 |\n\n## Competition\n${competitorSummary}\n\n## Rent\n${rentSummary}\n\n## Market Demand\n${demandSummary}\n\n## Cost Analysis\n${costSummary}\n\n## Profitability\n${profitSummary}\n\n## P&L\n${plSummary}\n\n## 3-Year Projection\n${projection}\n\n## Sensitivity\n${sensitivity}\n\n## SWOT\n${swotMarkdown}`;

return [{ json: {
  report_id:             d.report_id,
  submission_id:         d.submission_id,
  overall_score:         overallScore,
  verdict:               verdict,
  score_competition:     scoreCompetition,
  score_rent:            scoreRent,
  score_demand:          scoreDemand,
  score_cost:            scoreCost,
  score_profitability:   scoreProfit,
  recommendation:        verdict + ': ' + (overallScore >= 60 ? 'Proceed with the plan.' : 'Consider alternative locations.'),
  competitor_analysis:   competitorSummary,
  rent_analysis:         rentSummary,
  market_demand:         demandSummary,
  cost_analysis:         costSummary,
  profitability:         profitSummary,
  breakeven_monthly:     breakevenMonthly,
  breakeven_daily:       breakevenDaily,
  breakeven_months:      breakevenMonths,
  pl_summary:            plSummary,
  three_year_projection: projection,
  sensitivity_analysis:  sensitivity,
  swot_analysis:         swotMarkdown,
  full_report_markdown:  fullReport,
  result_data: {
    agent_statuses: { a1: d.a1_status, a2: d.a2_status, a3: d.a3_status, a4: d.a4_status, a5: d.a5_status, a6: d.a6_status, a7: d.a7_status, a8: d.a8_status },
    a1, a2, a3, a4, a5, a6, a7, a8,
    errors: { a1: d.a1_error, a2: d.a2_error, a3: d.a3_error, a4: d.a4_error, a5: d.a5_error, a6: d.a6_error, a7: d.a7_error, a8: d.a8_error }
  },
  input_data: {
    business_type: d.business_type, city: d.city, area: d.area,
    address: d.address, monthly_rent: d.monthly_rent, setup_cost: d.setup_cost,
    monthly_revenue: d.monthly_revenue, lat: d.lat, lng: d.lng
  },
  status:        'completed',
  location_name: d.area || d.city || '',
  business_type: d.business_type,
  address:       d.address || '',
  monthly_rent:  monthlyRent,
  user_id:       (d.user_id && d.user_id !== 'anonymous') ? d.user_id : null,
  completed_at:  new Date().toISOString()
}}];

const report = $('Build Report').first().json;
const supaResp = $input.first().json;
const supaOk = !(supaResp.statusCode && supaResp.statusCode >= 400);

return [{ json: {
  success:        true,
  report_id:      report.report_id,
  overall_score:  report.overall_score,
  verdict:        report.verdict,
  recommendation: report.recommendation,
  scores: {
    competition:  report.score_competition,
    rent:         report.score_rent,
    demand:       report.score_demand,
    cost:         report.score_cost,
    profitability: report.score_profitability
  },
  financials: {
    breakeven_monthly: report.breakeven_monthly,
    breakeven_daily:   report.breakeven_daily,
    breakeven_months:  report.breakeven_months,
    pl_summary:        report.pl_summary
  },
  supabase_saved:       supaOk,
  supabase_error:       supaOk ? null : JSON.stringify(supaResp).slice(0,300),
  full_report_markdown: report.full_report_markdown
}}];
